'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { doc, setDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';

interface Message { role: 'assistant' | 'user'; content: string; }

const SECTIONS = ['projects', 'skills', 'interests', 'working-style'] as const;
type Section = typeof SECTIONS[number];
const SECTION_LABELS: Record<Section, string> = {
  projects: 'Your Projects',
  skills: 'Skills & Tools',
  interests: 'Interests & Domains',
  'working-style': 'Working Style',
};
const QUESTIONS_PER_SECTION = 2;

export default function OnboardingPage() {
  const { user, refreshProfile } = useAuth();
  const router = useRouter();
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sectionIndex, setSectionIndex] = useState(0);
  const [sectionQCount, setSectionQCount] = useState(0);
  const [extracting, setExtracting] = useState(false);
  const [done, setDone] = useState(false);
  const [profile, setProfile] = useState<Record<string, unknown>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const currentSection = SECTIONS[sectionIndex] as Section;

  // Kick off the first question
  useEffect(() => {
    if (!user) return;
    askNextQuestion([]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const askNextQuestion = async (history: Message[]) => {
    setLoading(true);
    try {
      const res = await fetch('/api/nim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'onboard-message',
          payload: { conversationHistory: history, section: currentSection },
        }),
      });
      const { reply } = await res.json();
      setMessages((prev) => [...prev, { role: 'assistant', content: reply }]);
    } catch {
      setMessages((prev) => [...prev, { role: 'assistant', content: "Tell me more about yourself!" }]);
    } finally {
      setLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const userMsg: Message = { role: 'user', content: input.trim() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput('');

    const newCount = sectionQCount + 1;
    setSectionQCount(newCount);

    if (newCount >= QUESTIONS_PER_SECTION) {
      // Run background extraction for this section
      runExtraction(newMessages.map(m => `${m.role === 'user' ? 'Student' : 'Assistant'}: ${m.content}`).join('\n'));

      if (sectionIndex + 1 < SECTIONS.length) {
        // Next section transition
        const nextSection = SECTIONS[sectionIndex + 1];
        setSectionIndex((i) => i + 1);
        setSectionQCount(0);
        setMessages((prev) => [
          ...prev,
          { role: 'assistant', content: `Great! Now let's talk about ${SECTION_LABELS[nextSection]}.` },
        ]);
        setTimeout(() => askNextQuestion(newMessages), 600);
      } else {
        // All sections done
        await finalize(newMessages);
      }
    } else {
      await askNextQuestion(newMessages);
    }
  };

  const runExtraction = async (text: string) => {
    try {
      const res = await fetch('/api/nim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'extract-profile', payload: { conversationText: text } }),
      });
      const { extracted } = await res.json();
      if (extracted && !extracted.error) {
        setProfile((prev) => mergeExtracted(prev, extracted));
      }
    } catch { /* silent */ }
  };

  const finalize = async (history: Message[]) => {
    setExtracting(true);
    setMessages((prev) => [...prev, {
      role: 'assistant',
      content: "That's all I need! Building your profile now — this takes just a moment ✦",
    }]);

    // Final full extraction
    const fullText = history.map(m => `${m.role === 'user' ? 'Student' : 'Assistant'}: ${m.content}`).join('\n');
    let finalProfile = profile;
    try {
      const res = await fetch('/api/nim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'extract-profile', payload: { conversationText: fullText } }),
      });
      const { extracted } = await res.json();
      if (extracted && !extracted.error) {
        finalProfile = mergeExtracted(profile, extracted);
        setProfile(finalProfile);
      }
    } catch { /* use what we have */ }

    // Save to Firestore
    if (user) {
      const hardSkills = (finalProfile.hard_skills as Array<{ name: string }> ?? []).map(s => s.name);
      const softSkills = (finalProfile.soft_skills as Array<{ name: string }> ?? []).map(s => s.name);
      const interests = (finalProfile.interests as Array<{ name: string }> ?? []).map(s => s.name);
      const ws = finalProfile.working_style as Record<string, string> ?? {};

      const profileData = {
        uid: user.uid,
        headline: finalProfile.headline ?? '',
        aboutMe: finalProfile.bio ?? '',
        techSkills: hardSkills,
        nonTechSkills: softSkills,
        interests,
        workingStyle: ws,
        availabilityHoursPerWeek: finalProfile.availability_hours_per_week ?? 10,
        suggestedKeywords: finalProfile.suggested_keywords ?? [],
        profileCompleted: true,
        score: computeScore(hardSkills, softSkills),
        collaborationCount: 0,
        hackathons: [],
        papers: 0,
        patents: 0,
        certifications: [],
        internships: [],
        cgpa: 0,
        college: '',
        isStudent: true,
        isActive: true,
        dateJoined: new Date().toISOString(),
        codeName: generateCodeName(),
        github: '', linkedin: '', leetcode: '', codechef: '', hackerrank: '',
      };

      await setDoc(doc(db, 'users', user.uid), profileData, { merge: true });

      // Upsert to Pinecone (best effort)
      try {
        await fetch('/api/pinecone', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'upsert-candidate', payload: { uid: user.uid, profile: profileData } }),
        });
      } catch { /* graceful */ }
    }

    setExtracting(false);
    await refreshProfile?.();   // update context BEFORE showing done
    setDone(true);
  };

  // Auto-redirect to /swipe when done
  useEffect(() => {
    if (done) {
      const t = setTimeout(() => router.push('/swipe'), 1500);
      return () => clearTimeout(t);
    }
  }, [done, router]);

  const handleSkip = async () => {
    if (!user || loading) return;
    setExtracting(true);
    const minProfile = {
      uid: user.uid, headline: '', aboutMe: '',
      techSkills: [], nonTechSkills: [], interests: [],
      workingStyle: {}, availabilityHoursPerWeek: 10,
      suggestedKeywords: [], profileCompleted: true,
      score: 30, collaborationCount: 0, hackathons: [], papers: 0,
      patents: 0, certifications: [], internships: [], cgpa: 0,
      college: '', isStudent: true, isActive: true,
      dateJoined: new Date().toISOString(), codeName: generateCodeName(),
      github: '', linkedin: '', leetcode: '', codechef: '', hackerrank: '',
    };
    try {
      await setDoc(doc(db, 'users', user.uid), minProfile, { merge: true });
      await refreshProfile?.();
    } catch { /* graceful */ }
    setExtracting(false);
    router.push('/swipe');
  };

  if (done) {
    return (
      <div className="loading-page" style={{ flexDirection: 'column', gap: 16 }}>
        <div style={{ fontFamily: 'var(--font-dm-serif)', fontSize: 28 }}>You&apos;re in! ✦</div>
        <p style={{ color: 'var(--subtle)', fontSize: 14 }}>Heading to Discover...</p>
        <div className="spinner" style={{ marginTop: 8 }} />
      </div>
    );
  }

  const progress = ((sectionIndex * QUESTIONS_PER_SECTION + Math.min(sectionQCount, QUESTIONS_PER_SECTION)) / (SECTIONS.length * QUESTIONS_PER_SECTION)) * 100;

  return (
    <div className="app-shell" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <header className="c-header">
        <span className="c-logo">Campus<span>Link</span></span>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span className="nim-badge">✦ AI Interview</span>
          <button
            onClick={handleSkip}
            disabled={extracting}
            style={{ fontSize: 12, color: 'var(--subtle)', background: 'none', border: 'none', cursor: 'pointer', padding: '4px 8px' }}
          >
            Skip →
          </button>
        </div>
      </header>

      {/* Progress bar */}
      <div style={{ height: 3, background: 'var(--mid)' }}>
        <div style={{ height: '100%', background: 'var(--white)', width: `${progress}%`, transition: 'width 0.6s ease' }} />
      </div>

      {/* Section tabs */}
      <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
        {SECTIONS.map((s, i) => (
          <div key={s} style={{
            flex: 1, padding: '10px 4px', textAlign: 'center', fontSize: 10,
            textTransform: 'uppercase', letterSpacing: '0.5px',
            color: i === sectionIndex ? 'var(--white)' : i < sectionIndex ? 'var(--subtle)' : 'var(--muted)',
            borderBottom: i === sectionIndex ? '2px solid var(--white)' : '2px solid transparent',
            fontWeight: i === sectionIndex ? 600 : 400,
          }}>
            {i < sectionIndex ? '✓ ' : ''}{SECTION_LABELS[s]}
          </div>
        ))}
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '20px 16px', display: 'flex', flexDirection: 'column', gap: 12 }}>
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role === 'user' ? 'sent' : 'recv'}`} style={{ maxWidth: '85%' }}>
            {m.content}
          </div>
        ))}
        {loading && (
          <div className="msg recv" style={{ maxWidth: '85%' }}>
            <span style={{ opacity: 0.5 }}>✦ thinking...</span>
          </div>
        )}
        {extracting && (
          <div className="msg system">Extracting your profile with AI...</div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="chat-input-row" style={{ paddingBottom: 20 }}>
        <input
          ref={inputRef}
          className="chat-input"
          placeholder="Type your answer..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          disabled={loading || extracting}
        />
        <button className="send-btn" onClick={handleSend} disabled={loading || extracting}>➤</button>
      </div>
    </div>
  );
}

// ── Helpers ────────────────────────────────────────────────────────────────────

function mergeExtracted(prev: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
  const merged = { ...prev };
  for (const key of Object.keys(next)) {
    if (Array.isArray(next[key]) && Array.isArray(merged[key])) {
      // Merge arrays without duplicates
      const existing = (merged[key] as Array<{ name: string }>).map((x) => x.name ?? x);
      const incoming = (next[key] as Array<{ name: string }>).filter((x) => !existing.includes(x.name ?? x));
      merged[key] = [...(merged[key] as unknown[]), ...incoming];
    } else {
      merged[key] = next[key];
    }
  }
  return merged;
}

function computeScore(techSkills: string[], softSkills: string[]): number {
  return Math.min(100, 30 + techSkills.length * 5 + softSkills.length * 3);
}

function generateCodeName(): string {
  const adj = ['Swift', 'Bright', 'Sharp', 'Deep', 'Keen', 'Bold', 'Wise', 'Calm'];
  const noun = ['Falcon', 'Comet', 'Nexus', 'Cipher', 'Vector', 'Apex', 'Zephyr', 'Pulse'];
  return `${adj[Math.floor(Math.random() * adj.length)]} ${noun[Math.floor(Math.random() * noun.length)]}`;
}
